# Unit Tests for `camel_to_snake`

```python
import pytest


def camel_to_snake(s: str) -> str:
    import re
    return re.sub(r'(?<=[a-z])(?=[A-Z])', '_', s).lower()


class TestCamelToSnakeHappyPath:
    """Tests for typical, expected camelCase inputs."""

    def test_simple_camel_case(self):
        assert camel_to_snake("camelCase") == "camel_case"

    def test_multiple_words(self):
        assert camel_to_snake("thisIsATest") == "this_is_atest"

    def test_two_word_camel(self):
        assert camel_to_snake("helloWorld") == "hello_world"

    def test_long_camel_case(self):
        assert camel_to_snake("getUserNameFromDatabase") == "get_user_name_from_database"

    def test_pascal_case(self):
        # PascalCase: no lowercase before first uppercase, so no underscore prepended
        assert camel_to_snake("PascalCase") == "pascal_case"

    def test_pascal_case_multiple_words(self):
        assert camel_to_snake("MyClassName") == "my_class_name"


class TestCamelToSnakeEdgeCases:
    """Tests for edge cases and unusual inputs."""

    def test_empty_string(self):
        assert camel_to_snake("") == ""

    def test_single_lowercase_letter(self):
        assert camel_to_snake("a") == "a"

    def test_single_uppercase_letter(self):
        assert camel_to_snake("A") == "a"

    def test_all_lowercase(self):
        assert camel_to_snake("hello") == "hello"

    def test_all_uppercase(self):
        # No lowercase->uppercase boundary, so no underscores added
        assert camel_to_snake("HELLO") == "hello"

    def test_already_snake_case(self):
        assert camel_to_snake("already_snake_case") == "already_snake_case"

    def test_with_numbers(self):
        # Digits don't trigger boundary (regex only matches lowercase->uppercase)
        assert camel_to_snake("var1Name") == "var1_name"

    def test_uppercase_before_lowercase(self):
        # No underscore inserted between uppercase and lowercase
        assert camel_to_snake("ABCdef") == "abcdef"

    def test_consecutive_uppercase(self):
        # Acronyms: HTTPRequest -> no boundary inside HTTP, only at P->R? No: P is upper, R is upper
        assert camel_to_snake("HTTPRequest") == "httprequest"

    def test_consecutive_uppercase_after_lowercase(self):
        assert camel_to_snake("parseHTTPResponse") == "parse_httpresponse"

    def test_single_char_groups(self):
        assert camel_to_snake("aB") == "a_b"

    def test_with_underscore_already(self):
        assert camel_to_snake("myVar_name") == "my_var_name"

    def test_with_spaces(self):
        # Spaces are preserved, not converted
        assert camel_to_snake("hello World") == "hello world"

    def test_with_special_characters(self):
        assert camel_to_snake("foo$Bar") == "foo$_bar"

    def test_only_underscores(self):
        assert camel_to_snake("___") == "___"

    def test_unicode_lowercase_to_uppercase(self):
        # Regex \p classes aren't used; [a-z] and [A-Z] are ASCII only
        # So unicode boundaries should NOT be split
        assert camel_to_snake("привет") == "привет"

    def test_starts_with_uppercase_single_word(self):
        assert camel_to_snake("Hello") == "hello"

    def test_trailing_uppercase(self):
        assert camel_to_snake("varX") == "var_x"


class TestCamelToSnakeErrorCases:
    """Tests for invalid input types."""

    def test_none_raises_type_error(self):
        with pytest.raises(TypeError):
            camel_to_snake(None)

    def test_integer_raises_type_error(self):
        with pytest.raises(TypeError):
            camel_to_snake(123)

    def test_list_raises_type_error(self):
        with pytest.raises(TypeError):
            camel_to_snake(["camelCase"])

    def test_dict_raises_type_error(self):
        with pytest.raises(TypeError):
            camel_to_snake({"key": "value"})

    def test_bytes_raises_type_error(self):
        with pytest.raises(TypeError):
            camel_to_snake(b"camelCase")


class TestCamelToSnakeParametrized:
    """Parametrized tests covering multiple cases concisely."""

    @pytest.mark.parametrize("input_str,expected", [
        ("camelCase", "camel_case"),
        ("CamelCase", "camel_case"),
        ("simple", "simple"),
        ("", ""),
        ("a", "a"),
        ("A", "a"),
        ("aB", "a_b"),
        ("aBc", "a_bc"),
        ("aBcDe", "a_bc_de"),
        ("getHTTPResponse", "get_httpresponse"),
        ("XMLParser", "xmlparser"),
        ("iPhone", "i_phone"),
        ("snake_case_already", "snake_case_already"),
        ("123abc", "123abc"),
        ("camelCase123", "camel_case123"),
    ])
    def test_various_inputs(self, input_str, expected):
        assert camel_to_snake(input_str) == expected
